#include <stdio.h>
int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int b1, b2, b3; scanf("%d %d %d", &b1, &b2, &b3);
        int empty = (b1 == 0) + (b2 == 0) + (b3 == 0);
        if (empty >= 2) printf("Water filling time\n");
        else printf("Not now\n");
    }
    return 0;
}

