import java.io.*;
import java.util.*;
public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        int T = Integer.parseInt(br.readLine().trim());
        StringBuilder sb = new StringBuilder();
        for (int t = 0; t < T; t++) {
            StringTokenizer st = new StringTokenizer(br.readLine());
            int b1 = Integer.parseInt(st.nextToken());
            int b2 = Integer.parseInt(st.nextToken());
            int b3 = Integer.parseInt(st.nextToken());
            int empty = (b1==0 ? 1:0) + (b2==0 ? 1:0) + (b3==0 ? 1:0);
            if (empty >= 2) sb.append("Water filling time\n");
            else sb.append("Not now\n");
        }
        System.out.print(sb.toString());
    }
}

code.Python3:
#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        b1 = int(next(it)); b2 = int(next(it)); b3 = int(next(it))
        empty = (b1==0) + (b2==0) + (b3==0)
        out_lines.append("Water filling time" if empty >= 2 else "Not now")
    sys.stdout.write("\n".join(out_lines))

if __name__ == "__main__":
    solve()

